<script setup lang="ts">
import { computed,onMounted,ref } from 'vue'; import { useHealthCasesStore } from '@/stores/healthCases'; import PriorityBadge from '@/components/health/PriorityBadge.vue'
const store=useHealthCasesStore(); const selected=ref<string>('ALL'); onMounted(()=>store.loadCases()); const filtered=computed(()=>selected.value==='ALL'?store.cases:store.cases.filter(c=>c.status===selected.value))
</script>
<template><div class="page"><header><div><h1>Mis casos</h1><p>Historial de orientación, prioridad y seguimiento.</p></div><select v-model="selected" class="form-input"><option value="ALL">Todos</option><option value="NEW">Nuevos</option><option value="ORIENTED">Orientados</option><option value="PENDING_REVIEW">Revisión humana</option><option value="RESOLVED">Resueltos</option><option value="CLOSED">Cerrados</option></select></header><div v-if="!filtered.length" class="empty card">No hay casos con este filtro.</div><article v-for="item in filtered" :key="item.id" class="case card"><div class="top"><div><small>{{new Date(item.created_at).toLocaleString('es-EC')}}</small><h3>{{item.reason||'Orientación de salud'}}</h3></div><PriorityBadge :priority="item.priority_level" :score="item.priority_score"/></div><p>{{item.summary||'Sin resumen todavía.'}}</p><div class="meta"><span>Estado: <strong>{{item.status}}</strong></span><span>Sector: <strong>{{item.sector||'No indicado'}}</strong></span><span v-if="item.requires_human_review">👩‍⚕️ Revisión solicitada</span></div></article></div></template>
